def solve(weight_percent_data, porosity_data, organic_carbon_data):
    volume_percent_data = {}

    for mineral, weight_percent in weight_percent_data.items():
        # Convert weight percent to volume percent
        volume_percent_data[mineral] = weight_percent / (1 + (weight_percent / 100))

    # Integrate with porosity and organic carbon data
    for mineral in volume_percent_data:
        volume_percent_data[mineral] *= (1 - porosity_data.get(mineral, 0)) * (1 - organic_carbon_data.get(mineral, 0))

    return volume_percent_data
